class Solution {
public:
    bool isFascinating(int n) {
        string concatenated = to_string(n) + to_string(2 * n) + to_string(3 * n);
        if (concatenated.size() != 9) return false;
        bool seen[10] = {false};
        for (char c : concatenated) {
            int digit = c - '0';
            if (digit == 0 || seen[digit]) return false;
            seen[digit] = true;
        }
        return true;
    }
};
